package com.user.servlet; import com.DB.DBConnect; import com.DAO.UserDAOImpl; import com.entity.User; import javax.servlet.annotation.WebServlet; import javax.servlet.http.*; import java.io.*;
@WebServlet("/update_profile") public class UpdateProfileServlet extends HttpServlet {protected void doPost(HttpServletRequest r,HttpServletResponse p)throws IOException{HttpSession s=r.getSession();try(var c=DBConnect.getConn()){int id=Integer.parseInt(r.getParameter("id"));UserDAOImpl d=new UserDAOImpl(c);String pw=r.getParameter("password");if(!d.checkPassword(id,pw)){s.setAttribute("failedMsg","Wrong password");p.sendRedirect("edit_profile.jsp");return;}User u=new User();u.setId(id);u.setName(r.getParameter("fname"));u.setEmail(r.getParameter("email"));u.setPhono(r.getParameter("phono"));if(d.updateProfile(u)){User logged=(User)s.getAttribute("userobj");logged.setName(u.getName());logged.setEmail(u.getEmail());logged.setPhono(u.getPhono());s.setAttribute("succMsg","Profile updated successfully");}else s.setAttribute("failedMsg","Profile update failed");}catch(Exception e){s.setAttribute("failedMsg",e.getMessage());}p.sendRedirect("edit_profile.jsp");}}
